import{_ as e,p as a,q as n,a1 as s}from"./framework-5866ffd3.js";const i={},d=s(`<h1 id="fg" tabindex="-1"><a class="header-anchor" href="#fg" aria-hidden="true">#</a> fg</h1><p>将后台作业移动到前台终端运行</p><h2 id="概要" tabindex="-1"><a class="header-anchor" href="#概要" aria-hidden="true">#</a> 概要</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">fg</span> <span class="token punctuation">[</span>job_spec <span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="主要用途" tabindex="-1"><a class="header-anchor" href="#主要用途" aria-hidden="true">#</a> 主要用途</h2><ul><li><p>用于将后台作业（在后台运行的或者在后台挂起的作业）放到前台终端运行。</p></li><li><p>若后台任务中只有一个，则使用该命令时可以省略任务号。</p></li></ul><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><p>job_spec（可选）：指定要移动到前台执行的作业标识符，可以是一到多个。</p><h2 id="返回值" tabindex="-1"><a class="header-anchor" href="#返回值" aria-hidden="true">#</a> 返回值</h2><p>返回作业的执行状态，如果发生了错误返回失败。</p><h2 id="例子" tabindex="-1"><a class="header-anchor" href="#例子" aria-hidden="true">#</a> 例子</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 运行sleep命令，然后按下ctrl+z。</span>
<span class="token function">sleep</span> <span class="token number">60</span>
^Z
<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span>+  Stopped                 <span class="token function">sleep</span> <span class="token number">60</span>

<span class="token comment"># 使用fg命令使得作业在前台运行。</span>
<span class="token function">fg</span> %1

<span class="token comment"># 返回信息：</span>
<span class="token function">sleep</span> <span class="token number">60</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="注意" tabindex="-1"><a class="header-anchor" href="#注意" aria-hidden="true">#</a> 注意</h3><ol><li><code>bash</code>的作业控制命令包括<code>bg fg kill wait disown suspend</code>。</li><li>该命令需要<code>set</code>选项<code>monitor</code>处于开启状态时才能执行；查看作业控制状态：输入<code>set -o</code>查看<code>monitor</code>行；执行<code>set -o monitor</code>或<code>set -m</code>开启该选项。</li><li>该命令是bash内建命令，相关的帮助信息请查看<code>help</code>命令。</li></ol>`,14),c=[d];function l(o,t){return a(),n("div",null,c)}const p=e(i,[["render",l],["__file","fg.html.vue"]]);export{p as default};
